package tests.navigation.automated_ai;

import io.github.bonigarcia.wdm.WebDriverManager;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.chrome.ChromeDriver;
import org.openqa.selenium.chrome.ChromeOptions;
import org.openqa.selenium.support.ui.WebDriverWait;
import org.openqa.selenium.support.ui.ExpectedConditions;

import java.time.Duration;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Test class for PrestaShop demo shopping cart functionality.
 * Scenario: Add multiple quantities of the same product to cart.
 * URL: https://demo.prestashop.com/#/en/front
 */
public class AIAutomatedShoppingCart {

    private WebDriver driver;
    private WebDriverWait wait;
    private static final String PRESTASHOP_URL = "https://demo.prestashop.com/#/en/front";
    private static final Duration WAIT_DURATION = Duration.ofSeconds(10);

    /**
     * Setup: Initialize WebDriver and navigate to PrestaShop demo
     */
    @BeforeEach
    public void setUp() {
        // Setup ChromeDriver using WebDriverManager
        WebDriverManager.chromedriver().setup();

        ChromeOptions options = new ChromeOptions();
        options.addArguments("--remote-allow-origins=*");

        driver = new ChromeDriver(options);
        wait = new WebDriverWait(driver, WAIT_DURATION);

        // Configure driver timeouts
        driver.manage().timeouts().implicitlyWait(WAIT_DURATION);
        driver.manage().window().maximize();

        // Navigate to PrestaShop demo
        driver.get(PRESTASHOP_URL);

        // Wait for page to load
        wait.until(ExpectedConditions.presenceOfElementLocated(By.tagName("body")));
    }

    /**
     * Teardown: Close WebDriver
     */
    @AfterEach
    public void tearDown() {
        if (driver != null) {
            driver.quit();
        }
    }

    /**
     * Test: Add multiple quantities of the same product to cart
     */
    @Test
    public void testAddProductToCartAndCheckCount() {
        try {
            // Step 1: Switch to iframe
            wait.until(ExpectedConditions.frameToBeAvailableAndSwitchToIt(0));
            System.out.println("Switched to iframe successfully");

            // Step 1.5: Get initial cart count
            int initialCartCount = getCartCount();
            System.out.println("Initial cart count: " + initialCartCount);

            // Step 2: Click on product image/link to enter product details page
            WebElement productLink = wait.until(
                    ExpectedConditions.elementToBeClickable(
                            By.cssSelector("article.product-miniature a")
                    )
            );
            ((org.openqa.selenium.JavascriptExecutor) driver)
                    .executeScript("arguments[0].scrollIntoView({block: 'center'});", productLink);
            System.out.println("Clicking on product image to enter details page...");
            robustClick(productLink);

            // Step 3: Wait for product details page to load
            wait.until(ExpectedConditions.presenceOfElementLocated(
                    By.cssSelector("button.product__add-to-cart-button[data-button-action='add-to-cart']")
            ));
            System.out.println("Product details page loaded");

            // Step 4: Find and click "Add to cart" button on product details page
            WebElement addToCartButton = wait.until(
                    ExpectedConditions.visibilityOfElementLocated(
                        By.cssSelector("button.product__add-to-cart-button[data-button-action='add-to-cart']")
                    )
            );
            ((org.openqa.selenium.JavascriptExecutor) driver)
                    .executeScript("arguments[0].scrollIntoView({block: 'center'});", addToCartButton);
            System.out.println("Clicking 'Add to cart' button on product details page...");
            robustClick(addToCartButton);

            // Step 5: Handle modal popup if it appears
            handleModalIfPresent();

            // Step 6: Verify that product was added to cart by checking cart badge
            int afterAdd = getCartCount();
            System.out.println("Cart count after add: " + afterAdd);
            if (afterAdd == initialCartCount + 1) {
                System.out.println("Test passed: Cart count increased by 1");
            } else {
                System.out.println("Test failed: Cart count did not increase as expected");
                fail("Cart count did not increase as expected");
            }
        } catch (Exception e) {
            System.out.println("Test failed: " + e.getMessage());
            fail("Test failed with exception: " + e.getMessage());
        }
    }

    /**
     * Robust click utility: tries normal click, falls back to JS click if needed
     */
    private void robustClick(WebElement element) {
        try {
            wait.until(ExpectedConditions.elementToBeClickable(element));
            element.click();
        } catch (Exception e) {
            // Fallback to JS click
            ((org.openqa.selenium.JavascriptExecutor) driver)
                .executeScript("arguments[0].click();", element);
        }
    }

    /**
     * Helper method to handle modal popup if it appears
     */
    private void handleModalIfPresent() {
        try {
            // Wait briefly for modal to appear (max 3 seconds)
            WebDriverWait shortWait = new WebDriverWait(driver, Duration.ofSeconds(3));

            // Wait for modal to be visible
            WebElement modal = shortWait.until(
                    ExpectedConditions.visibilityOfElementLocated(
                            By.cssSelector("#blockcart-modal.show")
                    )
            );

            // Find and click the close button
            WebElement closeButton = modal.findElement(
                    By.cssSelector("button[data-bs-dismiss='modal']")
            );

            System.out.println("Modal popup found, closing it...");
            ((org.openqa.selenium.JavascriptExecutor) driver)
                    .executeScript("arguments[0].click();", closeButton);

            System.out.println("Modal closed successfully");

        } catch (org.openqa.selenium.TimeoutException e) {
            System.out.println("No modal popup appeared (this is okay)");
        }
    }

    /**
     * Helper method to verify product was added to cart
     */
    private void verifyProductAddedToCart() {
        try {
            // Wait for cart badge to be visible
            WebElement cartBadge = wait.until(
                    ExpectedConditions.visibilityOfElementLocated(By.cssSelector(".header-block__badge"))
            );

            String badgeText = cartBadge.getText();
            System.out.println("Cart badge value: " + badgeText);

            // Assert that cart count is greater than 0
            int cartCount = Integer.parseInt(badgeText.trim());
            assertTrue(cartCount > 0, "Cart should contain at least 1 product");

        } catch (NumberFormatException e) {
            fail("Cart badge does not contain a valid number: " + e.getMessage());
        }
    }

    /**
     * Helper method to add the same product to cart again
     */
    private void addProductToCartAgain() {
        try {
            // Click on the same product image/link again to enter product details page
            WebElement productLink = wait.until(
                    ExpectedConditions.elementToBeClickable(
                            By.cssSelector("article.product-miniature a")
                    )
            );
            ((org.openqa.selenium.JavascriptExecutor) driver)
                    .executeScript("arguments[0].scrollIntoView({block: 'center'});", productLink);
            System.out.println("Clicking on product image again to enter details page...");
            robustClick(productLink);

            // Wait for product details page to load
            wait.until(ExpectedConditions.presenceOfElementLocated(
                    By.cssSelector("button.product__add-to-cart-button[data-button-action='add-to-cart']")
            ));

            // Find and click "Add to cart" button on product details page
            WebElement addToCartButton = wait.until(
                    ExpectedConditions.visibilityOfElementLocated(
                        By.cssSelector("button.product__add-to-cart-button[data-button-action='add-to-cart']")
                    )
            );
            ((org.openqa.selenium.JavascriptExecutor) driver)
                    .executeScript("arguments[0].scrollIntoView({block: 'center'});", addToCartButton);
            System.out.println("Adding same product to cart again...");
            robustClick(addToCartButton);

            // Handle modal if it appears again
            handleModalIfPresent();

        } catch (Exception e) {
            fail("Failed to add product again: " + e.getMessage());
        }
    }

    /**
     * Helper method to verify cart count has increased
     */
    private void verifyCartCountIncreased() {
        try {
            // Get updated cart badge count
            WebElement cartBadge = wait.until(
                    ExpectedConditions.visibilityOfElementLocated(By.cssSelector(".header-block__badge"))
            );

            String finalBadgeText = cartBadge.getText();
            int finalCartCount = Integer.parseInt(finalBadgeText.trim());

            // Assert that we have 2 products in cart
            assertEquals(2, finalCartCount, "Cart should contain 2 products");
            System.out.println("Final cart count verified: " + finalCartCount);

        } catch (NumberFormatException e) {
            fail("Failed to parse final cart count: " + e.getMessage());
        }
    }

    /**
     * Helper method to navigate back to home page
     */
    private void navigateBackToHomePage() {
        try {
            System.out.println("Navigating back to home page...");
            driver.navigate().back();

            // Wait for home page to load
            wait.until(ExpectedConditions.presenceOfElementLocated(By.tagName("body")));
            System.out.println("Returned to home page");

        } catch (Exception e) {
            fail("Failed to navigate back to home page: " + e.getMessage());
        }
    }

    /**
     * Helper to get the current cart count from the badge
     */
    private int getCartCount() {
        WebElement cartBadge = wait.until(
            ExpectedConditions.visibilityOfElementLocated(By.cssSelector(".header-block__badge"))
        );
        String badgeText = cartBadge.getText().trim();
        try {
            return Integer.parseInt(badgeText);
        } catch (NumberFormatException e) {
            return 0;
        }
    }
}
